from dataclasses import dataclass
from typing import Any


@dataclass
class Constraint:
    pass


class UnexpectedTypeException(Exception):
    def __init__(self, value: Any, expected_type: str) -> None:
        self.value = value
        self.expected_type = expected_type
        super().__init__(f"Expected type {expected_type}, got {type(value).__name__}")


class ConstraintValidator:
    def validate(self, value: Any, constraint: Constraint) -> bool:
        raise NotImplementedError("Subclasses should implement this!")


class LengthValidator(ConstraintValidator):
    def validate(self, value: Any, constraint: Constraint) -> bool:
        if not isinstance(value, (int, float)):
            raise UnexpectedTypeException(value, 'integer')

        if value < 0:
            raise UnexpectedTypeException(value, 'integer')

        if value > 100:
            raise UnexpectedTypeException(value, 'integer')

        return True
